const items = $input.all();
const diasSemana = ['Domingo', 'Segunda', 'TerГ§a', 'Quarta', 'Quinta', 'Sexta', 'SГЎbado'];
const hoje = new Date();
const diaStr = diasSemana[hoje.getDay()];
const dataStr = hoje.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' });

const fmt = (v) => parseFloat(v || 0).toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

const results = [];

for (const item of items) {
  const d = item.json;
  const isPremium = d.plano === 'premium';
  const nomeEmpresa = d.nome_empresa || 'Sua empresa';

  let msg = `вҳҖпёҸ *Bom dia, ${nomeEmpresa}!* вҖў ${diaStr}, ${dataStr}`;

  // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ ONTEM в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
  const temOntem = d.ontem_checkins > 0 || d.ontem_recebido > 0 || d.ontem_matriculas > 0 || d.ontem_leads > 0;
  if (temOntem) {
    msg += `\n\nрҹ“Ҡ *ONTEM*`;
    if (d.ontem_checkins > 0) msg += `\nвң… ${d.ontem_checkins} check-in${d.ontem_checkins > 1 ? 's' : ''}`;
    if (d.ontem_recebido > 0) msg += `\nрҹ’° R$ ${fmt(d.ontem_recebido)} recebidos`;
    if (d.ontem_matriculas > 0) msg += `\nрҹҶ• ${d.ontem_matriculas} matrГӯcula${d.ontem_matriculas > 1 ? 's' : ''} nova${d.ontem_matriculas > 1 ? 's' : ''} (${d.ontem_matriculas_nomes})`;
    if (d.ontem_leads > 0) msg += `\nрҹ“© ${d.ontem_leads} lead${d.ontem_leads > 1 ? 's' : ''} novo${d.ontem_leads > 1 ? 's' : ''}`;
    if (isPremium && d.ontem_nps_count > 0) msg += `\nвӯҗ ${d.ontem_nps_count} NPS (mГ©dia ${d.ontem_nps_media})`;
  }

  // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ FOCO DO DIA в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
  const temFoco = d.atencao_leads_sem_resposta > 0 || d.atencao_atrasados > 0 || d.atencao_risco_evasao > 0 || d.hoje_vencimentos > 0;
  if (temFoco) {
    msg += `\n\nрҹҺҜ *FOCO DO DIA*`;
    if (d.atencao_leads_sem_resposta > 0) msg += `\nвҡ пёҸ ${d.atencao_leads_sem_resposta} lead${d.atencao_leads_sem_resposta > 1 ? 's' : ''} aguardando resposta`;
    if (d.atencao_atrasados > 0) msg += `\nвҡ пёҸ ${d.atencao_atrasados} cobranГ§a${d.atencao_atrasados > 1 ? 's' : ''} em atraso (R$ ${fmt(d.atencao_atrasados_valor)})`;
    if (isPremium && d.atencao_risco_evasao > 0) msg += `\nвҡ пёҸ ${d.atencao_risco_evasao} aluno${d.atencao_risco_evasao > 1 ? 's' : ''} em risco de evasГЈo`;
    if (d.hoje_vencimentos > 0) msg += `\nрҹ’ё ${d.hoje_vencimentos} mensalidade${d.hoje_vencimentos > 1 ? 's' : ''} vence${d.hoje_vencimentos > 1 ? 'm' : ''} hoje (R$ ${fmt(d.hoje_vencimentos_valor)})`;
  }

  // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ AGENDA DE HOJE в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
  const allAulas = d.hoje_aulas_detalhe || [];
  const aulasComAluno = allAulas.filter(a => (a.total_fixos || 0) + (a.total_agendados || 0) > 0);
  msg += `\n\nрҹ“… *AGENDA DE HOJE*`;
  if (aulasComAluno.length > 0) {
    for (const aula of aulasComAluno) {
      const horario = aula.horario ? String(aula.horario).substring(0, 5) : '--:--';
      const total = (aula.total_fixos || 0) + (aula.total_agendados || 0);
      msg += `\nрҹ•җ ${horario}`;
      if (aula.descricao) msg += ` - ${aula.descricao}`;
      msg += ` (${total}/${aula.capacidade})`;
      const nomes = [aula.nomes_fixos, aula.nomes_agendados].filter(Boolean).join(', ');
      if (nomes) msg += `\n${nomes}`;
    }
  } else {
    msg += `\nрҹ“Ӣ Sem aulas confirmadas pra hoje`;
  }

  // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ ANIVERSARIANTE в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
  if (d.hoje_aniversariantes > 0) {
    msg += `\n\nрҹҺӮ *ANIVERSARIANTE${d.hoje_aniversariantes > 1 ? 'S' : ''}*`;
    const nomes = (d.hoje_aniversariantes_nomes || '').split(', ');
    for (const nome of nomes) {
      if (nome.trim()) msg += `\nрҹҺҲ ${nome.trim()} (Mandar parabГ©ns!)`;
    }
  }

  // в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ MГҠS (Premium) в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
  if (isPremium && d.mes_mrr > 0) {
    msg += `\n\nрҹ“Ҳ *MГҠS:* R$ ${fmt(d.mes_recebido)} de R$ ${fmt(d.mes_mrr)} (${d.mes_percentual_meta}%)`;
    if (d.mes_novos > 0 || d.mes_cancelamentos > 0) {
      msg += ` вҖў +${d.mes_novos} novo${d.mes_novos > 1 ? 's' : ''}`;
      if (d.mes_cancelamentos > 0) msg += ` -${d.mes_cancelamentos} saГӯda${d.mes_cancelamentos > 1 ? 's' : ''}`;
    }
  }

  msg += `\n\n_${nomeEmpresa} вҖў Mensalli_`;

  let telefone = String(d.telefone_admin || '').replace(/\D/g, '');
  if (!telefone.startsWith('55')) telefone = '55' + telefone;

  results.push({
    json: {
      user_id: d.user_id,
      plano: d.plano,
      mensagem: msg,
      telefone,
      evolution_url: `${d.evolution_api_url || 'http://service-evolution-api:8080'}/message/sendText/${d.evolution_instance_name}`,
      evolution_api_key: d.evolution_api_key
    }
  });
}

return results;

const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const data = items[i].json;
  if (i > 0) await new Promise(r => setTimeout(r, 2000));

  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: data.evolution_url,
      headers: { 'Content-Type': 'application/json', 'apikey': data.evolution_api_key },
      body: { number: data.telefone, text: data.mensagem },
      returnFullResponse: true,
      json: true
    });

    const body = resp.body;
    if (body?.key?.id) {
      results.push({ json: { ...data, envio_sucesso: true } });
    } else {
      results.push({ json: { ...data, envio_sucesso: false, erro: body?.message || 'Sem key.id' } });
    }
  } catch (err) {
    results.push({ json: { ...data, envio_sucesso: false, erro: err.message } });
  }
}

return results;
